/**
 * MedX accordion runtime — runs on `npm run start` via medx-runtime-registry.cjs
 * Collapsible sections for shipment details, audit logs, and compliance documents.
 */
const ACCORDION_SECTIONS = Object.freeze({
  shipmentDetails: {
    title: "Shipment details",
    defaultOpen: true,
    content: ["carrier", "trackingNumber", "estimatedDelivery", "originWarehouse"],
  },
  lineItems: {
    title: "Line items",
    defaultOpen: false,
    content: ["skuList", "quantities", "lotNumbers", "expiryDates"],
  },
  temperatureLog: {
    title: "Temperature log",
    defaultOpen: false,
    content: ["readings", "breachEvents", "sensorCalibration"],
  },
  complianceDocs: {
    title: "Compliance documents",
    defaultOpen: false,
    content: ["coa", "msds", "importPermit", "chainOfCustody"],
  },
  auditTrail: {
    title: "Audit trail",
    defaultOpen: false,
    content: ["createdBy", "modifiedBy", "statusHistory", "blockchainTx"],
  },
});

const accordionInstances = new Map();

function createAccordion(id, sectionKeys, options = {}) {
  const sections = sectionKeys.map((key) => {
    const meta = ACCORDION_SECTIONS[key];
    if (!meta) throw new Error(`Unknown accordion section: ${key}`);
    return {
      key,
      title: meta.title,
      open: meta.defaultOpen ?? false,
      fields: meta.content,
      contentLoaded: meta.defaultOpen ?? false,
    };
  });

  const instance = {
    id,
    sections,
    allowMultiple: options.allowMultiple ?? false,
    onToggle: typeof options.onToggle === "function" ? options.onToggle : null,
  };
  accordionInstances.set(id, instance);
  return instance;
}

function toggleSection(accordionId, sectionKey) {
  const instance = accordionInstances.get(accordionId);
  if (!instance) return false;
  const section = instance.sections.find((s) => s.key === sectionKey);
  if (!section) return false;

  const willOpen = !section.open;
  if (willOpen && !instance.allowMultiple) {
    for (const s of instance.sections) {
      if (s.key !== sectionKey) s.open = false;
    }
  }
  section.open = willOpen;
  if (willOpen) section.contentLoaded = true;
  if (instance.onToggle) instance.onToggle({ accordionId, sectionKey, open: willOpen });
  return true;
}

function expandAll(accordionId) {
  const instance = accordionInstances.get(accordionId);
  if (!instance) return false;
  for (const section of instance.sections) {
    section.open = true;
    section.contentLoaded = true;
  }
  return true;
}

function collapseAll(accordionId) {
  const instance = accordionInstances.get(accordionId);
  if (!instance) return false;
  for (const section of instance.sections) {
    section.open = false;
  }
  return true;
}

function getAccordionState(accordionId) {
  const instance = accordionInstances.get(accordionId);
  if (!instance) return null;
  return {
    id: instance.id,
    openSections: instance.sections.filter((s) => s.open).map((s) => s.key),
    loadedSections: instance.sections.filter((s) => s.contentLoaded).map((s) => s.key),
    totalSections: instance.sections.length,
  };
}

async function runMedxAccordion() {
  console.log("[medx:ui:accordion] runtime initialized");
  console.log(`[medx:ui:accordion] sectionTemplates=${Object.keys(ACCORDION_SECTIONS).length}`);

  const shipmentAccordion = createAccordion(
    "shipment-detail",
    ["shipmentDetails", "lineItems", "temperatureLog", "complianceDocs", "auditTrail"],
    { allowMultiple: false },
  );

  toggleSection("shipment-detail", "lineItems");
  toggleSection("shipment-detail", "temperatureLog");
  toggleSection("shipment-detail", "complianceDocs");

  const multiAccordion = createAccordion("docs-multi", ["complianceDocs", "auditTrail"], {
    allowMultiple: true,
  });
  expandAll("docs-multi");

  console.log(`[medx:ui:accordion] instances=${accordionInstances.size}`);
  console.log("[medx:ui:accordion] shipment", getAccordionState("shipment-detail"));
  console.log("[medx:ui:accordion] bootstrap complete");
}

module.exports = runMedxAccordion;
